// SecureVote frontend JS placeholder
(function(){
  // CSRF placeholder hook (the project currently uses a placeholder value in login.html)
  // Real CSRF should be generated by a PHP endpoint; left for future integration.
  try{
    const el = document.querySelector('input[name="csrf_token"]');
    if(el && !el.value) el.value = 'csrf-placeholder';
  }catch(e){}
})();

